with open(projectinfo_file, 'r') as f:
    project_info = json.load(f)

# Create lookup set for MIT packages
mit_lookup = set((pkg['Name'].lower(), pkg['Version']) for pkg in mit_packages)

# Process in chunks to avoid memory issues
def process_projects():
    project_stats = {}

    # First pass: count MIT packages per project
    for pv in project_versions:
        key = (pv.get('Name', '').lower(), pv.get('Version', ''))
        if key in mit_lookup:
            proj_name = pv.get('ProjectName', '')
            if proj_name:
                if proj_name not in project_stats:
                    project_stats[proj_name] = {'packages': 0, 'forks': 0}
                project_stats[proj_name]['packages'] += 1

    return project_stats

# Extract fork counts from project info
fork_counts = {}
for proj in project_info:
    info = proj.get('Project_Information', '')
    fork_match = re.search(r'forks[^\d]*(\d+)', info, re.IGNORECASE)
    if fork_match:
        forks = int(fork_match.group(1))
        # Extract project name
        proj_match = re.search(r'(?:project|repository)\s+([\w\-]+/[\w\-]+)', info, re.IGNORECASE)
        if proj_match:
            proj_name = proj_match.group(1)
            fork_counts[proj_name] = forks

# Get project statistics
project_stats = process_projects()

# Add fork counts
for proj_name in project_stats:
    if proj_name in fork_counts:
        project_stats[proj_name]['forks'] = fork_counts[proj_name]

# Filter projects with both packages and forks, sort by forks
valid_projects = [
    {'name': name, 'packages': stats['packages'], 'forks': stats['forks']}
    for name, stats in project_stats.items()
    if stats['forks'] > 0
]

valid_projects.sort(key=lambda x: x['forks'], reverse=True)

result = {
    'total_mit_packages': len(mit_packages),
    'matched_projects': len(valid_projects),
    'top_5': valid_projects[:5]
}

print('__RESULT__:')
